                      }
                    }
                  }
                }
              }
            },
            "code": {
              "type": "object",
              "properties": {
                "text": {
                  "type": "string",
                  "description": "The flowsheet ID, encoded flowsheet ID, or LOINC codes to flowsheet mapping. What is being measured."
                }
              }
            },
            "effectiveDateTime": {
              "type": "string",
              "description": "The date and time the observation was taken, in ISO format."
            },
            "status": {
              "type": "string",
